You can create a Node.js application using the code below. This code utilizes the 'http' module and a promise-based approach to check the validity of each link on a web page.

```javascript
const http = require('http');

const checkUrl = (url) => {
  return new Promise((resolve, reject) => {
    http
      .get(url, (res) => {
        const { statusCode } = res;
        const valid = statusCode >= 200 && statusCode < 400;
        resolve({ url, valid });
      })
      .on('error', (err) => {
        reject(err);
      });
  });
};

const checkPageLinks = async (url) => {
