import (
    "encoding/json"
    "fmt"
    "io/ioutil"
    "net/http"
)
func getWeatherData(lat float64, lon float64) (map[string]interface{}, error) {
    apiKey := "your-api-key"
    url := fmt.Sprintf("https://api.openweathermap.org/data/2.5/onecall?lat=%f&lon=%f&exclude=current,minutely,hourly,alerts&appid=%s", lat, lon, apiKey)
    resp, err := http.Get(url)
