        return nil, err
    }
    defer resp.Body.Close()
    body, err := ioutil.ReadAll(resp.Body)
    if err != nil {
        return nil, err
    }
    var data map[string]interface{}
    err = json.Unmarshal(body, &data)
    if err != nil {
        return nil, err
    }
    return data, nil
}
```
2. Process Data: Once you have collected the data, you can use Go libraries like time and math to process and analyze it. For example, you can calculate the average temperature and precipitation for each month of the winter season:
```
func getWinterData(data map[string]interface{}) (map[string]float64, error) {
    winterData := make(map[string]float64)
    for _, dailyData := range data["daily"].([]interface{}) {
        date := time.Unix(int64(dailyData.(map[string]interface{})["dt"].(float64)), 0)
        month := date.Month().String()
        if month == "December" || month == "January" || month == "February" {
