    frostDays := 0
    for _, dailyData := range data["daily"].([]interface{}) {
        if dailyData.(map[string]interface{})["temp"].(map[string]interface{})["min"].(float64) < 0 {
            frostDays++
        }
    }
    return frostDays, nil
